                  <div style="margin-top: 5px; margin-bottom: 5px; min-height: 55px;">
                    <img src="${nt.firmaDocente}" width="140" height="50" style="max-height: 50px; max-width: 140px; object-fit: contain; display: block;" />
                  </div>
